package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class UnsafeAllocatorTest {

  @Test
  void assertInstantiable_noException() throws Exception {
    // Arrange
    Class<?> clazz = String.class;

    // Mock ConstructorConstructor.checkInstantiable to return null (class is instantiable)
    // Use reflection to replace the method temporarily
    Method checkInstantiableMethod = ConstructorConstructor.class.getDeclaredMethod("checkInstantiable", Class.class);
    checkInstantiableMethod.setAccessible(true);

    // Save original method via proxy or use a spy on ConstructorConstructor if possible
    // Since it's static, we cannot mock easily without a framework like PowerMockito
    // Instead, we test the real method behavior by calling assertInstantiable on a known instantiable class

    // Act & Assert
    // Should not throw any exception
    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);
    assertDoesNotThrow(() -> assertInstantiableMethod.invoke(null, clazz));
  }

  @Test
  void assertInstantiable_throwsAssertionError() throws Exception {
    // Arrange
    Class<?> clazz = AbstractListSubclass.class;

    // We cannot mock static method ConstructorConstructor.checkInstantiable easily without PowerMockito,
    // so we create a dummy class that triggers the exception message.
    // Alternatively, use reflection to replace the method, but it's complex.
    // Instead, we create a dummy class that is non-instantiable and check that assertion error is thrown.

    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);

    AssertionError thrown = assertThrows(InvocationTargetException.class, () -> {
      try {
        assertInstantiableMethod.invoke(null, clazz);
      } catch (InvocationTargetException e) {
        // unwrap AssertionError
        if (e.getCause() instanceof AssertionError) {
          throw e;
        }
        throw e;
      }
    });

    Throwable cause = thrown.getCause();
    assertTrue(cause instanceof AssertionError);
    assertTrue(cause.getMessage().startsWith("UnsafeAllocator is used for non-instantiable type:"));
  }

  // A dummy abstract class to simulate non-instantiable class for the test
  abstract static class AbstractListSubclass extends java.util.AbstractList<Object> {
    @Override
    public Object get(int index) { return null; }
    @Override
    public int size() { return 0; }
  }
}
